mapper.select:
select

from run_events
where run_id = #{runId}
  and seq = #{seq}

select

from run_events
where run_id = #{runId}
  and session_id = #{sessionId}
  and raw_event_id = #{rawEventId}

select

from run_events
where run_id = #{runId}
  and seq > #{lastSeq}
order by seq asc
limit #{limit}

